// ╔══════════════════════════════════════════════════════════╗
// ║   NODE 3: AUTO-DETECT ALL COLUMNS + FULL STATISTICS     ║
// ║   Works with ANY Google Sheet — no config needed        ║
// ╚══════════════════════════════════════════════════════════╝

const allItems = $input.all();

if (!allItems || allItems.length === 0) {
  throw new Error('No data from Google Sheets. Check: Sheet ID, credential access, and that Row 1 has headers.');
}

const rows = allItems.map(i => i.json).filter(r => r && Object.keys(r).filter(k => r[k] !== '' && r[k] !== null).length > 0);

if (rows.length === 0) {
  throw new Error('Sheet has no valid data rows. Ensure data starts from Row 2.');
}

const columns = Object.keys(rows[0]);
const total = rows.length;

// ── TYPE DETECTION ──────────────────────────────────────────
const toNum = v => parseFloat(String(v || '').replace(/[,%$]/g, ''));
const isNum = v => v !== '' && v !== null && v !== undefined && !isNaN(toNum(v)) && String(v).trim() !== '';
const isDate = v => /\d{1,4}[\/-]\d{1,2}[\/-]\d{2,4}/.test(String(v));

const numCols = [], catCols = [], dateCols = [];

columns.forEach(col => {
  const vals = rows.map(r => r[col]).filter(v => v !== '' && v !== null && v !== undefined);
  if (vals.length === 0) return;
  const numRatio = vals.filter(v => isNum(v)).length / vals.length;
  const dateRatio = vals.filter(v => isDate(v)).length / vals.length;
  if (numRatio >= 0.7) numCols.push(col);
  else if (dateRatio >= 0.5) dateCols.push(col);
  else catCols.push(col);
});

// ── NUMERIC STATS ────────────────────────────────────────────
const numStats = {};
numCols.forEach(col => {
  const vals = rows.map(r => toNum(r[col])).filter(v => !isNaN(v));
  if (!vals.length) return;
  vals.sort((a, b) => a - b);
  const n = vals.length;
  const sum = vals.reduce((a, b) => a + b, 0);
  const mean = sum / n;
  const med = n % 2 === 0 ? (vals[n/2-1] + vals[n/2]) / 2 : vals[Math.floor(n/2)];
  const std = Math.sqrt(vals.reduce((a, v) => a + (v - mean) ** 2, 0) / n);
  numStats[col] = {
    count: n, missing: total - n,
    min: +vals[0].toFixed(2), max: +vals[n-1].toFixed(2),
    mean: +mean.toFixed(2), median: +med.toFixed(2),
    std: +std.toFixed(2),
    q1: +vals[Math.floor(n*0.25)].toFixed(2),
    q3: +vals[Math.floor(n*0.75)].toFixed(2),
    completeness: +((n/total)*100).toFixed(1)
  };
});

// ── CATEGORICAL STATS ────────────────────────────────────────
const catStats = {};
catCols.forEach(col => {
  const freq = {};
  rows.forEach(r => {
    const v = String(r[col] || 'Unknown').trim();
    freq[v] = (freq[v] || 0) + 1;
  });
  const sorted = Object.entries(freq).sort((a, b) => b[1] - a[1]);
  catStats[col] = {
    unique: sorted.length,
    missing: rows.filter(r => !r[col] || r[col] === '').length,
    completeness: +((rows.filter(r => r[col] && r[col] !== '').length / total) * 100).toFixed(1),
    topValues: sorted.slice(0, 10).map(([value, count]) => ({ value, count, pct: +((count/total)*100).toFixed(1) }))
  };
});

// ── DETECT SPECIAL COLUMNS ───────────────────────────────────
const findCol = (keywords) => columns.find(c => keywords.some(k => c.toLowerCase().includes(k)));
const riskCol   = findCol(['risk','severity','status','level','priority','stage','condition','grade']);
const nameCol   = findCol(['name','patient','person','subject','client']);
const ageCol    = numCols.find(c => c.toLowerCase().includes('age'));
const genderCol = catCols.find(c => c.toLowerCase().includes('gender') || c.toLowerCase().includes('sex'));
const diagCol   = catCols.find(c => c.toLowerCase().includes('diagnosis') || c.toLowerCase().includes('condition') || c.toLowerCase().includes('disease'));
const doctorCol = catCols.find(c => c.toLowerCase().includes('doctor') || c.toLowerCase().includes('physician') || c.toLowerCase().includes('provider'));

// ── ANOMALY DETECTION (>2σ) ──────────────────────────────────
const anomalies = [];
Object.entries(numStats).forEach(([col, s]) => {
  if (s.std === 0) return;
  rows.forEach(r => {
    const v = toNum(r[col]);
    if (!isNaN(v) && Math.abs(v - s.mean) > 2 * s.std) {
      anomalies.push({
        record: nameCol ? String(r[nameCol] || 'Unknown') : 'Record',
        col, value: v, mean: s.mean,
        sigma: +((v - s.mean) / s.std).toFixed(1)
      });
    }
  });
});
const topAnomalies = anomalies.sort((a,b) => Math.abs(b.sigma)-Math.abs(a.sigma)).slice(0, 8);

// ── OVERALL COMPLETENESS ─────────────────────────────────────
let filled = 0, totalF = 0;
rows.forEach(r => columns.forEach(c => { totalF++; if (r[c] !== '' && r[c] !== null && r[c] !== undefined) filled++; }));
const completeness = +((filled/totalF)*100).toFixed(1);

// ── CHART DATA PREPARATION ───────────────────────────────────
// Each chart is pre-built as data arrays for Chart.js
const charts = {};

// Chart A: Primary categorical (doughnut)
const primaryCat = riskCol || diagCol || genderCol || catCols[0];
if (primaryCat && catStats[primaryCat]) {
  charts.doughnut = { col: primaryCat, labels: catStats[primaryCat].topValues.slice(0,7).map(v=>v.value), values: catStats[primaryCat].topValues.slice(0,7).map(v=>v.count) };
}

// Chart B: Second categorical (horizontal bar)
const secondCat = catCols.find(c => c !== primaryCat) || catCols[1];
if (secondCat && catStats[secondCat]) {
  charts.hbar = { col: secondCat, labels: catStats[secondCat].topValues.slice(0,8).map(v=>v.value), values: catStats[secondCat].topValues.slice(0,8).map(v=>v.count) };
}

// Chart C: Age / primary numeric histogram
if (ageCol && numStats[ageCol]) {
  const s = numStats[ageCol];
  const bkt = Math.max(1, Math.ceil((s.max - s.min) / 7));
  const buckets = {};
  rows.forEach(r => {
    const v = toNum(r[ageCol]);
    if (!isNaN(v)) {
      const k = Math.floor((v - s.min) / bkt) * bkt + s.min;
      const label = `${k}-${k+bkt}`;
      buckets[label] = (buckets[label]||0) + 1;
    }
  });
  charts.histogram = { col: ageCol, labels: Object.keys(buckets), values: Object.values(buckets) };
}

// Chart D: Second numeric histogram
const num2Col = numCols.find(c => c !== ageCol);
if (num2Col && numStats[num2Col]) {
  const s = numStats[num2Col];
  const bkt = Math.max(1, Math.ceil((s.max - s.min) / 6));
  const bkts = {};
  rows.forEach(r => {
    const v = toNum(r[num2Col]);
    if (!isNaN(v)) {
      const k = Math.floor((v - s.min) / bkt) * bkt + s.min;
      bkts[`${k}-${k+bkt}`] = (bkts[`${k}-${k+bkt}`]||0) + 1;
    }
  });
  charts.histogram2 = { col: num2Col, labels: Object.keys(bkts), values: Object.values(bkts) };
}

// Chart E: Gender (pie) if available
if (genderCol && catStats[genderCol]) {
  charts.pie = { col: genderCol, labels: catStats[genderCol].topValues.slice(0,5).map(v=>v.value), values: catStats[genderCol].topValues.slice(0,5).map(v=>v.count) };
}

// Chart F: Min/Mean/Max grouped bar across numeric columns
if (numCols.length >= 2) {
  const top5 = numCols.slice(0, 5);
  charts.grouped = { labels: top5, mins: top5.map(c=>numStats[c]?.min||0), means: top5.map(c=>numStats[c]?.mean||0), maxs: top5.map(c=>numStats[c]?.max||0) };
}

// Chart G: Doctor/Provider distribution (if exists)
if (doctorCol && catStats[doctorCol]) {
  charts.doctor = { col: doctorCol, labels: catStats[doctorCol].topValues.slice(0,6).map(v=>v.value), values: catStats[doctorCol].topValues.slice(0,6).map(v=>v.count) };
}

return [{ json: {
  meta: { total, columns, numCols, catCols, dateCols, completeness, riskCol, nameCol, ageCol, genderCol, diagCol, doctorCol, reportId: `RPT-${Date.now()}`, ts: new Date().toISOString() },
  numStats, catStats, charts, topAnomalies, rows: rows.slice(0,5)
}}];

// ╔══════════════════════════════════════════════════════════╗
// ║   NODE 4: BUILD AI PROMPT FROM DETECTED DATA            ║
// ╚══════════════════════════════════════════════════════════╝

const d = $input.first().json;
const { meta, numStats, catStats, topAnomalies } = d;

const numSummary = Object.entries(numStats).map(([c,s]) =>
  `${c}: min=${s.min}, max=${s.max}, mean=${s.mean}, median=${s.median}, std=${s.std}, missing=${s.missing}`
).join('\n') || 'No numeric columns';

const catSummary = Object.entries(catStats).map(([c,s]) =>
  `${c} (${s.unique} values): ${s.topValues.slice(0,5).map(v=>`${v.value}=${v.count}(${v.pct}%)`).join(', ')}`
).join('\n') || 'No categorical columns';

const anomSummary = topAnomalies.length > 0
  ? topAnomalies.map(a => `  ${a.record}: ${a.col}=${a.value} (${a.sigma}σ from mean ${a.mean})`).join('\n')
  : '  None detected';

const prompt = `You are a senior clinical informatics analyst. Analyze ${meta.total} patient health records.

COLUMNS (${meta.columns.length}): ${meta.columns.join(', ')}
DATA COMPLETENESS: ${meta.completeness}%

NUMERIC STATISTICS:
${numSummary}

CATEGORICAL BREAKDOWN:
${catSummary}

OUTLIERS/ANOMALIES (>2 std deviations):
${anomSummary}

Respond ONLY with valid JSON (no markdown, no extra text) using EXACTLY this structure:
{
  "summary": "3-paragraph executive health summary covering population status, data quality, and critical patterns",
  "dataQuality": {"score": "94%", "grade": "Excellent|Good|Fair|Poor", "issues": ["string"], "fixes": ["string"]},
  "findings": [{"title": "string", "detail": "string", "severity": "critical|warning|info"}],
  "risk": {"score": 7, "level": "High|Medium|Low", "trend": "Increasing|Stable|Decreasing", "factors": ["string"], "groups": ["string"]},
  "insights": [{"col": "column name", "finding": "what the data shows", "action": "what to do"}],
  "alerts": [{"who": "record identifier", "issue": "specific concern", "action": "what to do", "urgency": "immediate|soon|monitor"}],
  "predictions": [{"outcome": "string", "probability": "65%", "basis": "string", "timeframe": "3 months", "prevention": "string"}],
  "recommendations": [{"priority": "high|medium|low", "category": "string", "rec": "specific recommendation", "rationale": "evidence", "impact": "expected result", "when": "timeline"}],
  "segments": [{"name": "string", "size": "string", "traits": "string", "needs": "string"}],
  "ops": {"staffing": "string", "resources": "string", "improvements": ["string"]},
  "conclusion": "2-paragraph conclusion with overall assessment and top 3 priorities"
}`;

return [{ json: { ...d, prompt } }];

// ╔══════════════════════════════════════════════════════════╗
// ║   NODE 6: PARSE AI RESPONSE — FULL GRACEFUL FALLBACK    ║
// ╚══════════════════════════════════════════════════════════╝

const resp = $input.first().json;
const prev = $('📝 Build AI Prompt').first().json;
const { meta, numStats, catStats, charts, topAnomalies } = prev;

let ai = null;
try {
  let raw = resp?.choices?.[0]?.message?.content
         || resp?.content?.[0]?.text
         || (typeof resp === 'string' ? resp : JSON.stringify(resp));
  raw = raw.replace(/^```json\s*/gi,'').replace(/^```\s*/gi,'').replace(/\s*```$/gi,'').trim();
  ai = JSON.parse(raw);
} catch(e) {
  // Full fallback — workflow never fails
  ai = {
    summary: `Analysis of ${meta.total} records across ${meta.columns.length} columns completed. Data completeness is ${meta.completeness}%. ${meta.numCols.length} numeric metrics and ${meta.catCols.length} categorical dimensions were analyzed. Statistical processing identified ${topAnomalies.length} outliers requiring review.`,
    dataQuality: { score: meta.completeness+'%', grade: meta.completeness>=90?'Excellent':meta.completeness>=75?'Good':'Fair', issues: [], fixes: [] },
    findings: [{ title: 'Dataset Processed Successfully', detail: `${meta.total} records, ${meta.columns.length} columns, ${topAnomalies.length} anomalies detected.`, severity: 'info' }],
    risk: { score: 5, level: 'Medium', trend: 'Stable', factors: ['Review flagged anomalies'], groups: [] },
    insights: Object.keys(numStats).slice(0,3).map(c => ({ col: c, finding: `Mean: ${numStats[c].mean}, Range: ${numStats[c].min}–${numStats[c].max}`, action: 'Monitor values outside normal range' })),
    alerts: topAnomalies.slice(0,4).map(a => ({ who: a.record, issue: `${a.col} = ${a.value} (${a.sigma}σ from mean)`, action: 'Clinical review recommended', urgency: Math.abs(a.sigma)>3?'immediate':'monitor' })),
    predictions: [],
    recommendations: [{ priority: 'high', category: 'Data Quality', rec: 'Review records with missing fields', rationale: `${100-meta.completeness}% data missing`, impact: 'Improved analytical accuracy', when: 'This week' }],
    segments: [],
    ops: { staffing: 'Standard staffing levels appropriate', resources: 'No immediate reallocation needed', improvements: ['Complete missing data fields'] },
    conclusion: `Report generated from ${meta.total} records. Statistical analysis is complete and accurate. Clinical AI narrative was unavailable this run — all chart and table data is valid.`
  };
}

const now = new Date();
return [{ json: {
  ai,
  meta, numStats, catStats, charts, topAnomalies,
  rpt: {
    id: meta.reportId,
    date: now.toLocaleDateString('en-US',{weekday:'long',year:'numeric',month:'long',day:'numeric'}),
    time: now.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',hour12:true}),
    iso: now.toISOString()
  }
}}];

// ╔══════════════════════════════════════════════════════════╗
// ║   NODE 7: BUILD STUNNING HTML DASHBOARD                 ║
// ║   Charts: Doughnut, Pie, Horizontal Bar, Vertical Bar,  ║
// ║           Histogram x2, Grouped Bar, Radar, Polar Area  ║
// ╚══════════════════════════════════════════════════════════╝

const { ai, meta, numStats, catStats, charts, topAnomalies, rpt } = $input.first().json;

const safe = (v, fb='N/A') => (v!==null&&v!==undefined&&v!=='') ? v : fb;
const clamp = (v,a,b) => Math.min(Math.max(Number(v)||0,a),b);
const pct = (a,b) => b>0 ? ((a/b)*100).toFixed(1) : '0.0';
const sc = (s) => ({critical:'#ff4757',warning:'#ffa502',info:'#1e90ff',high:'#ff4757',medium:'#ffa502',low:'#2ed573',immediate:'#ff4757',soon:'#ffa502',monitor:'#1e90ff'})[String(s||'').toLowerCase()]||'#636e72';

const riskScore = clamp(ai.risk?.score||5, 1, 10);
const riskPct = riskScore*10;
const riskClr = riskScore>=7?'#ff4757':riskScore>=4?'#ffa502':'#2ed573';

// ── PALETTE ──────────────────────────────────────────────────
const P = ['#00d2ff','#a29bfe','#fd79a8','#fdcb6e','#55efc4','#e17055','#74b9ff','#ff7675','#00cec9','#6c5ce7','#fab1a0','#81ecec'];
const PA = (i, alpha=0.85) => { const c=P[i%P.length]; const r=parseInt(c.slice(1,3),16),g=parseInt(c.slice(3,5),16),b=parseInt(c.slice(5,7),16); return `rgba(${r},${g},${b},${alpha})`; };

// ── CHART BUILDER FUNCTION ───────────────────────────────────
// Returns an HTML <canvas> block with inline Chart.js config
const makeChart = (id, config) => `
<div class="chart-card">
  <canvas id="c${id}"></canvas>
  <script>(function(){try{new Chart(document.getElementById('c${id}').getContext('2d'),${JSON.stringify(config)});}catch(e){document.getElementById('c${id}').parentElement.innerHTML='<div class="chart-err">Chart unavailable</div>';}}());</script>
</div>`;

// ── BUILD INDIVIDUAL CHARTS ──────────────────────────────────
const chartHTML = [];

// 1. DOUGHNUT — Primary categorical
if (charts.doughnut) {
  const { col, labels, values } = charts.doughnut;
  chartHTML.push(makeChart('dnut', {
    type: 'doughnut',
    data: { labels, datasets: [{ data: values, backgroundColor: labels.map((_,i)=>PA(i)), borderColor: '#0d1117', borderWidth: 3, hoverOffset: 12 }] },
    options: { responsive:true, cutout:'65%', plugins: { legend:{ position:'bottom', labels:{color:'#e2e8f0',font:{size:11},padding:10,boxWidth:12}}, title:{display:true,text:col+' Distribution',color:'#f1f5f9',font:{size:13,weight:'bold'},padding:{bottom:10}} } }
  }));
}

// 2. PIE — Gender or second categorical
if (charts.pie) {
  const { col, labels, values } = charts.pie;
  chartHTML.push(makeChart('pie', {
    type: 'pie',
    data: { labels, datasets: [{ data: values, backgroundColor: labels.map((_,i)=>PA(i+3)), borderColor:'#0d1117', borderWidth:3, hoverOffset:10 }] },
    options: { responsive:true, plugins:{ legend:{position:'bottom',labels:{color:'#e2e8f0',font:{size:11},padding:10,boxWidth:12}}, title:{display:true,text:col,color:'#f1f5f9',font:{size:13,weight:'bold'},padding:{bottom:10}} } }
  }));
}

// 3. HORIZONTAL BAR — Category breakdown
if (charts.hbar) {
  const { col, labels, values } = charts.hbar;
  chartHTML.push(makeChart('hbar', {
    type: 'bar',
    data: { labels, datasets: [{ label: 'Count', data: values, backgroundColor: labels.map((_,i)=>PA(i,0.8)), borderColor: labels.map((_,i)=>P[i%P.length]), borderWidth:1, borderRadius:6 }] },
    options: { indexAxis:'y', responsive:true, plugins:{ legend:{display:false}, title:{display:true,text:col+' Breakdown',color:'#f1f5f9',font:{size:13,weight:'bold'},padding:{bottom:10}} }, scales:{ x:{ticks:{color:'#94a3b8'},grid:{color:'rgba(255,255,255,0.06)'}}, y:{ticks:{color:'#cbd5e1',font:{size:11}},grid:{display:false}} } }
  }));
}

// 4. VERTICAL BAR — Histogram for primary numeric
if (charts.histogram) {
  const { col, labels, values } = charts.histogram;
  chartHTML.push(makeChart('hist1', {
    type: 'bar',
    data: { labels, datasets: [{ label: col, data: values, backgroundColor: labels.map((_,i)=>PA(i,0.75)), borderColor: P[0], borderWidth:1, borderRadius:5 }] },
    options: { responsive:true, plugins:{ legend:{display:false}, title:{display:true,text:col+' Distribution',color:'#f1f5f9',font:{size:13,weight:'bold'},padding:{bottom:10}} }, scales:{ x:{ticks:{color:'#94a3b8',font:{size:10}},grid:{display:false}}, y:{ticks:{color:'#94a3b8'},grid:{color:'rgba(255,255,255,0.06)'}} } }
  }));
}

// 5. VERTICAL BAR — Histogram for second numeric
if (charts.histogram2) {
  const { col, labels, values } = charts.histogram2;
  chartHTML.push(makeChart('hist2', {
    type: 'bar',
    data: { labels, datasets: [{ label: col, data: values, backgroundColor: labels.map((_,i)=>PA(i+2,0.75)), borderColor: P[2], borderWidth:1, borderRadius:5 }] },
    options: { responsive:true, plugins:{ legend:{display:false}, title:{display:true,text:col+' Distribution',color:'#f1f5f9',font:{size:13,weight:'bold'},padding:{bottom:10}} }, scales:{ x:{ticks:{color:'#94a3b8',font:{size:10}},grid:{display:false}}, y:{ticks:{color:'#94a3b8'},grid:{color:'rgba(255,255,255,0.06)'}} } }
  }));
}

// 6. GROUPED BAR — Min/Mean/Max across numeric columns
if (charts.grouped && charts.grouped.labels.length >= 2) {
  const g = charts.grouped;
  chartHTML.push(makeChart('grp', {
    type: 'bar',
    data: { labels: g.labels, datasets: [
      { label:'Min',  data:g.mins,  backgroundColor:'rgba(46,213,115,0.7)',  borderColor:'#2ed573', borderWidth:1, borderRadius:4 },
      { label:'Mean', data:g.means, backgroundColor:'rgba(0,210,255,0.7)',   borderColor:'#00d2ff', borderWidth:1, borderRadius:4 },
      { label:'Max',  data:g.maxs,  backgroundColor:'rgba(255,71,87,0.7)',   borderColor:'#ff4757', borderWidth:1, borderRadius:4 }
    ]},
    options: { responsive:true, plugins:{ legend:{labels:{color:'#e2e8f0',font:{size:11}}}, title:{display:true,text:'Numeric Metrics — Min / Mean / Max',color:'#f1f5f9',font:{size:13,weight:'bold'},padding:{bottom:10}} }, scales:{ x:{ticks:{color:'#94a3b8',font:{size:10}},grid:{display:false}}, y:{ticks:{color:'#94a3b8'},grid:{color:'rgba(255,255,255,0.06)'}} } }
  }));
}

// 7. RADAR — Completeness per numeric column
if (meta.numCols.length >= 3) {
  const radarCols = meta.numCols.slice(0,7);
  chartHTML.push(makeChart('radar', {
    type: 'radar',
    data: { labels: radarCols, datasets: [{
      label: 'Data Completeness %',
      data: radarCols.map(c => numStats[c]?.completeness||0),
      backgroundColor: 'rgba(108,92,231,0.25)',
      borderColor: '#6c5ce7', borderWidth: 2,
      pointBackgroundColor: '#a29bfe', pointRadius: 5
    }]},
    options: { responsive:true, scales:{ r:{ angleLines:{color:'rgba(255,255,255,0.1)'}, grid:{color:'rgba(255,255,255,0.1)'}, pointLabels:{color:'#cbd5e1',font:{size:10}}, ticks:{color:'#64748b',backdropColor:'transparent',font:{size:9}} } }, plugins:{ legend:{labels:{color:'#e2e8f0'}}, title:{display:true,text:'Column Completeness Radar',color:'#f1f5f9',font:{size:13,weight:'bold'},padding:{bottom:10}} } }
  }));
}

// 8. POLAR AREA — Category distribution
const polarCat = Object.keys(catStats).find(c => catStats[c].topValues.length >= 3);
if (polarCat) {
  const pvs = catStats[polarCat].topValues.slice(0,6);
  chartHTML.push(makeChart('polar', {
    type: 'polarArea',
    data: { labels: pvs.map(v=>v.value), datasets: [{ data: pvs.map(v=>v.count), backgroundColor: pvs.map((_,i)=>PA(i+1,0.75)), borderColor: '#0d1117', borderWidth:2 }] },
    options: { responsive:true, scales:{ r:{ ticks:{color:'#64748b',backdropColor:'transparent'}, grid:{color:'rgba(255,255,255,0.08)'} } }, plugins:{ legend:{position:'right',labels:{color:'#e2e8f0',font:{size:10},padding:8,boxWidth:10}}, title:{display:true,text:polarCat+' (Polar)',color:'#f1f5f9',font:{size:13,weight:'bold'},padding:{bottom:10}} } }
  }));
}

// 9. LINE — Doctor/Provider workload if available
if (charts.doctor) {
  const { col, labels, values } = charts.doctor;
  chartHTML.push(makeChart('line', {
    type: 'line',
    data: { labels, datasets: [{ label: 'Patient Load', data: values, borderColor:'#fd79a8', backgroundColor:'rgba(253,121,168,0.15)', fill:true, tension:0.4, pointBackgroundColor:'#fd79a8', pointRadius:5, pointHoverRadius:8 }] },
    options: { responsive:true, plugins:{ legend:{display:false}, title:{display:true,text:col+' Patient Load',color:'#f1f5f9',font:{size:13,weight:'bold'},padding:{bottom:10}} }, scales:{ x:{ticks:{color:'#94a3b8',font:{size:10}},grid:{display:false}}, y:{ticks:{color:'#94a3b8'},grid:{color:'rgba(255,255,255,0.06)'}} } }
  }));
}

